import React, { useState } from "react";
import Navbar from "../components/Navbar";
import { api } from "../lib/api";
import { toast } from "sonner";
import { Mail, Github, Twitter } from "lucide-react";

export default function Contact() {
  const [form, setForm] = useState({ name: "", email: "", subject: "", message: "" });
  const [busy, setBusy] = useState(false);
  const [done, setDone] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setBusy(true);
    try {
      await api.post("/contact", form);
      setDone(true);
      toast.success("message received");
      setForm({ name: "", email: "", subject: "", message: "" });
    } catch (err) {
      toast.error(err?.response?.data?.detail || "failed to send");
    } finally { setBusy(false); }
  };

  return (
    <div className="min-h-screen bg-black text-white">
      <Navbar floating={false} />
      <div className="max-w-5xl mx-auto px-6 md:px-10 pt-12 pb-16 grid md:grid-cols-2 gap-16">
        <div>
          <p className="text-white/50 text-sm mb-2">say hi</p>
          <h1 className="hero-title text-6xl md:text-7xl font-medium mb-6" data-testid="contact-title">contact us</h1>
          <p className="text-white/60 mb-8">whether you want to collaborate, sponsor a hackathon, or just learn more about spectral forge — we'd love to hear from you.</p>

          <div className="space-y-4 text-sm">
            <div className="flex items-center gap-3 text-white/70">
              <Mail size={16} className="text-white/40" />
              <span>spectral.forge.official@gmail.com</span>
            </div>
            <div className="flex items-center gap-3 text-white/70">
              <Github size={16} className="text-white/40" />
              <span>github.com/spectral-forge</span>
            </div>
            <div className="flex items-center gap-3 text-white/70">
              <Twitter size={16} className="text-white/40" />
              <span>@spectralforge</span>
            </div>
          </div>
        </div>

        <div>
          {done ? (
            <div className="bg-neutral-900/60 border border-white/10 rounded-3xl p-8 text-center" data-testid="contact-success">
              <p className="text-3xl mb-2">thanks ✦</p>
              <p className="text-white/60 text-sm mb-4">we got your message. someone from the forge will reach out soon.</p>
              <button onClick={() => setDone(false)} className="text-sm underline text-white/70 hover:text-white">send another</button>
            </div>
          ) : (
            <form onSubmit={submit} className="space-y-3" data-testid="contact-form">
              <input required value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="your name" data-testid="contact-name" className="w-full bg-neutral-900/90 border border-white/10 rounded-full px-5 py-3 text-sm placeholder-white/40 focus:outline-none focus:border-white/30" />
              <input required type="email" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} placeholder="your email" data-testid="contact-email" className="w-full bg-neutral-900/90 border border-white/10 rounded-full px-5 py-3 text-sm placeholder-white/40 focus:outline-none focus:border-white/30" />
              <input required value={form.subject} onChange={(e) => setForm({ ...form, subject: e.target.value })} placeholder="subject" data-testid="contact-subject" className="w-full bg-neutral-900/90 border border-white/10 rounded-full px-5 py-3 text-sm placeholder-white/40 focus:outline-none focus:border-white/30" />
              <textarea required value={form.message} onChange={(e) => setForm({ ...form, message: e.target.value })} placeholder="your message" rows={6} data-testid="contact-message" className="w-full bg-neutral-900/90 border border-white/10 rounded-3xl px-5 py-4 text-sm placeholder-white/40 focus:outline-none focus:border-white/30 resize-none" />
              <button type="submit" disabled={busy} data-testid="contact-submit" className="w-full bg-white text-black rounded-full py-3 text-sm hover:bg-neutral-200 transition-colors disabled:opacity-50">
                {busy ? "sending..." : "send message"}
              </button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}
